namespace sv_cafe09f484e9498994f4111f0c9fd5c7.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that holds the currently selected warehouse for one user circuit.
/// Raises <see cref="OnChange"/> so any subscribing component can re-render.
/// </summary>
public sealed class WarehouseStateService
{
    private string _currentWarehouseId = "WH1";

    public static IReadOnlyList<WarehouseInfo> AvailableWarehouses { get; } =
    [
        new() { Id = "WH1", Name = "Warehouse A – East" },
        new() { Id = "WH2", Name = "Warehouse B – West" },
        new() { Id = "WH3", Name = "Warehouse C – Central" },
    ];

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_cafe09f484e9498994f4111f0c9fd5c7.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts on a timer.
/// Any component can subscribe to <see cref="OnAlertCountChanged"/> to
/// be notified when fresh data arrives — enabling cross-component updates
/// without parent-child relationships.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();

    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private int _lastAlertCount;

    public int LastAlertCount => _lastAlertCount;

    /// <summary>
    /// Fired on the polling thread whenever a new alert count is fetched.
    /// Subscribers must marshal to their own sync context (InvokeAsync) before
    /// calling StateHasChanged.
    /// </summary>
    public event Func<Task>? OnAlertCountChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query – returns a random number 0-15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component becomes visible and wants polling to run.
    /// Polling starts on the first subscriber and stops when the last unsubscribes.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>Call when a component is disposed or leaves the page.</summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _cts?.Dispose();
            _cts = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        // Fetch immediately on start, then every 10 seconds.
        await FetchAndNotifyAsync();

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await FetchAndNotifyAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on disposal / navigation away.
        }
    }

    private async Task FetchAndNotifyAsync()
    {
        _lastAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);

        if (OnAlertCountChanged is { } handler)
        {
            await handler.Invoke();
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

