@page "/dashboard"
@rendermode InteractiveServer
@using sv_cafe09f484e9498994f4111f0c9fd5c7.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Currently viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="card mt-4" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text">
            Items below minimum stock level:
            <span class="badge rounded-pill @BadgeClass fs-5 ms-2">@_alertCount</span>
        </p>
        <p class="text-muted small mb-0">
            Auto-refreshes every 10 seconds. Last update: @_lastUpdated.ToString("HH:mm:ss")
        </p>
    </div>
</div>

@code {
    private int _alertCount;
    private DateTime _lastUpdated = DateTime.Now;

    private string BadgeClass => _alertCount > 0 ? "bg-danger" : "bg-success";

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertCountChanged += HandleAlertChanged;

        // Start polling while this page is visible.
        AlertService.StartPolling();
    }

    private void HandleWarehouseChanged() => InvokeAsync(async () =>
    {
        // Warehouse changed — fetch fresh alert count immediately.
        _alertCount = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastUpdated = DateTime.Now;
        StateHasChanged();
    });

    private Task HandleAlertChanged() => InvokeAsync(() =>
    {
        _alertCount = AlertService.LastAlertCount;
        _lastUpdated = DateTime.Now;
        StateHasChanged();
    });

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertCountChanged -= HandleAlertChanged;
        AlertService.StopPolling();
    }
}

